import { EventEmitter } from 'events';
import { BrowserWindow } from 'electron';
import { SSHService } from './SSHService';
import { CredentialVault } from './CredentialVault';
import { RegistryService, createRegistryService } from './RegistryService';
import { NixpacksService } from './NixpacksService';
import { TraefikDynamicRouter, createTraefikDynamicRouter } from './TraefikDynamicRouter';
import { TraefikService } from './TraefikService';
import { ZeroDowntimeDeployer, createZeroDowntimeDeployer } from './docker-stack/ZeroDowntimeDeployer';
import { DockerStackLogger } from './docker-stack/logger';
import { db } from '../db';
import type {
  ContainerInfo,
  DeployStackInput,
  LogEntry,
  RedeployOptions,
  StackDeploymentResult,
  StackStatusInfo,
} from './docker-stack/types';
import { deployStack } from './docker-stack/deploy';
import { redeployStack } from './docker-stack/redeploy';
import { rollbackStack } from './docker-stack/rollback';
import {
  redeployZeroDowntime,
  rollbackZeroDowntime,
  updateDeploymentStrategy,
} from './docker-stack/zeroDowntime';
import { updateBuildLocation } from './docker-stack/buildLocation';
import {
  deleteStack,
  getDeploymentHistory,
  getStack,
  getStatus,
  listStacks,
  restartStack,
  startStack,
  stopStack,
  streamLogs,
  updateComposeFile,
  updateEnvVars,
  getContainerStatusForStack,
} from './docker-stack/runtime';
import { getAllContainers, getContainerStats } from './docker-stack/containers';
import { clearPendingFailure } from './docker-stack/deploymentDb';
import type { DockerStackServiceContext } from './docker-stack/context';
import { createEnvFile, ensureEnvFileDirective } from './docker-stack/env';
import { ensureDockerInstalled, uploadFile } from './docker-stack/system';

export type {
  ContainerInfo,
  DeployStackInput,
  DeploymentStatus,
  LogEntry,
  RedeployOptions,
  SourceType,
  StackDeploymentResult,
  StackStatus,
  StackStatusInfo,
  TriggerType,
} from './docker-stack/types';

export class DockerStackService extends EventEmitter {
  private sshService: SSHService;
  private registryService: RegistryService;
  private nixpacksService: NixpacksService;
  private traefikRouter: TraefikDynamicRouter;
  private traefikService: TraefikService;
  private zeroDowntimeDeployer: ZeroDowntimeDeployer;
  private mainWindow: BrowserWindow | null = null;
  private logger: DockerStackLogger;

  constructor(sshService: SSHService, credentialVault: CredentialVault) {
    super();
    this.sshService = sshService;
    this.registryService = createRegistryService(credentialVault, sshService);

    this.nixpacksService = new NixpacksService(sshService);

    this.traefikRouter = createTraefikDynamicRouter(sshService);
    this.traefikService = new TraefikService(sshService);
    this.zeroDowntimeDeployer = createZeroDowntimeDeployer(sshService, this.traefikRouter);

    this.logger = new DockerStackLogger({
      windowProvider: () => this.mainWindow,
      eventEmitter: this,
      persistDeploymentLogs: this.persistDeploymentLogs.bind(this),
    });
  }

  setMainWindow(window: BrowserWindow) {
    this.mainWindow = window;
    this.zeroDowntimeDeployer.setMainWindow(window);
  }

  private emitLog(message: string, type: LogEntry['type'] = 'info', stackId?: string, deploymentId?: string) {
    this.logger.emit(message, type, stackId, deploymentId);
  }

  private saveDeploymentLogs(deploymentId: string): void {
    this.logger.saveDeploymentLogs(deploymentId);
  }

  private initDeploymentLogs(deploymentId: string): void {
    this.logger.initDeploymentLogs(deploymentId);
  }

  private persistDeploymentLogs(deploymentId: string, logsText: string): void {
    const stmt = db.prepare(`
      UPDATE docker_stack_deployments SET logs = ? WHERE id = ?
    `);
    stmt.run(logsText, deploymentId);
  }

  private buildContext(): DockerStackServiceContext {
    const emitLog = this.emitLog.bind(this);
    const upload = (serverId: string, path: string, content: string) =>
      uploadFile(this.sshService, serverId, path, content);

    return {
      sshService: this.sshService,
      registryService: this.registryService,
      nixpacksService: this.nixpacksService,
      traefikService: this.traefikService,
      zeroDowntimeDeployer: this.zeroDowntimeDeployer,
      emitLog,
      initDeploymentLogs: this.initDeploymentLogs.bind(this),
      saveDeploymentLogs: this.saveDeploymentLogs.bind(this),
      uploadFile: upload,
      ensureDockerInstalled: (serverId: string) =>
        ensureDockerInstalled(this.sshService, emitLog, serverId),
      createEnvFile: (serverId: string, workingDir: string, envVars: Record<string, string>) =>
        createEnvFile(upload, serverId, workingDir, envVars),
      ensureEnvFileDirective: (serverId: string, workingDir: string, stackId: string) =>
        ensureEnvFileDirective({
          sshService: this.sshService,
          uploadFile: upload,
          emitLog,
          serverId,
          workingDir,
          stackId,
        }),
    };
  }

  async deploy(input: DeployStackInput): Promise<StackDeploymentResult> {
    return deployStack(this.buildContext(), input);
  }

  async redeploy(
    serverId: string,
    stackId: string,
    options: RedeployOptions = {}
  ): Promise<StackDeploymentResult> {
    return redeployStack(this.buildContext(), serverId, stackId, options);
  }

  async redeployZeroDowntime(
    serverId: string,
    stackId: string,
    options: RedeployOptions = {}
  ): Promise<StackDeploymentResult> {
    return redeployZeroDowntime(this.buildContext(), serverId, stackId, options);
  }

  async rollbackZeroDowntime(
    serverId: string,
    stackId: string,
    targetDeploymentId: string
  ): Promise<StackDeploymentResult> {
    return rollbackZeroDowntime(this.buildContext(), serverId, stackId, targetDeploymentId);
  }

  async rollback(
    serverId: string,
    stackId: string,
    targetDeploymentId: string
  ): Promise<StackDeploymentResult> {
    return rollbackStack(this.buildContext(), serverId, stackId, targetDeploymentId);
  }

  async updateDeploymentStrategy(
    serverId: string,
    stackId: string,
    strategy: 'standard' | 'zero_downtime'
  ): Promise<void> {
    return updateDeploymentStrategy(this.buildContext(), serverId, stackId, strategy);
  }

  async updateBuildLocation(
    serverId: string,
    stackId: string,
    buildLocation: 'vps' | 'github-actions' | 'local-build'
  ): Promise<void> {
    return updateBuildLocation(this.buildContext(), serverId, stackId, buildLocation);
  }

  async start(serverId: string, stackId: string): Promise<void> {
    return startStack(this.buildContext(), serverId, stackId);
  }

  async stop(serverId: string, stackId: string, removeVolumes: boolean = false): Promise<void> {
    return stopStack(this.buildContext(), serverId, stackId, removeVolumes);
  }

  async restart(serverId: string, stackId: string, serviceName?: string): Promise<void> {
    return restartStack(this.buildContext(), serverId, stackId, serviceName);
  }

  async delete(serverId: string, stackId: string, removeVolumes: boolean = false, force: boolean = false): Promise<void> {
    return deleteStack(this.buildContext(), serverId, stackId, removeVolumes, force);
  }

  async getStatus(serverId: string, stackId: string): Promise<StackStatusInfo | null> {
    return getStatus(this.buildContext(), serverId, stackId);
  }

  async listStacks(serverId: string) {
    return listStacks(this.buildContext(), serverId);
  }

  getStack(stackId: string) {
    return getStack(this.buildContext(), stackId);
  }

  async updateComposeFile(serverId: string, stackId: string, content: string): Promise<void> {
    return updateComposeFile(this.buildContext(), serverId, stackId, content);
  }

  async updateEnvVars(
    serverId: string,
    stackId: string,
    envVars: Record<string, string>
  ): Promise<void> {
    return updateEnvVars(this.buildContext(), serverId, stackId, envVars);
  }

  getDeploymentHistory(stackId: string, limit: number = 10) {
    return getDeploymentHistory(this.buildContext(), stackId, limit);
  }

  async *streamLogs(
    serverId: string,
    stackId: string,
    serviceName?: string,
    tail: number = 100
  ): AsyncGenerator<string> {
    for await (const chunk of streamLogs(this.buildContext(), serverId, stackId, serviceName, tail)) {
      yield chunk;
    }
  }

  clearPendingFailure(stackId: string): void {
    clearPendingFailure(stackId);
  }

  async getAllContainers(serverId: string): Promise<Map<string, ContainerInfo[]>> {
    return getAllContainers(this.buildContext(), serverId);
  }

  async getContainerStats(serverId: string): Promise<Map<string, { cpu: string; mem: string; memPerc: string }>> {
    return getContainerStats(this.buildContext(), serverId);
  }

  async getContainerStatus(serverId: string, workingDir: string): Promise<ContainerInfo[]> {
    return getContainerStatusForStack(this.buildContext(), serverId, workingDir);
  }
}

export function createDockerStackService(
  sshService: SSHService,
  credentialVault: CredentialVault
): DockerStackService {
  return new DockerStackService(sshService, credentialVault);
}
